### **9. Account Resolution (`src/accounts.ts`)**

**Top-level (Nostr pattern):**
```typescript
import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import { listCombinedAccountIds, resolveListedDefaultAccountId } 
  from "openclaw/plugin-sdk/account-resolution";
import { normalizeSecretInputString } from "openclaw/plugin-sdk/secret-input";
import type { OpenClawConfig } from "../api.js";

export function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const pbCfg = (cfg.channels as Record<string, unknown> | undefined)?.pulseboard;
  const privateKey = normalizeSecretInputString(pbCfg?.privateKey);
  return listCombinedAccountIds({
    configuredAccountIds: [],
    implicitAccountId: privateKey ? (DEFAULT_ACCOUNT_ID) : undefined,
  });
}

export function resolveDefaultPulseBoardAccountId(cfg: OpenClawConfig): string {
  const accountIds = listPulseBoardAccountIds(cfg);
  return resolveListedDefaultAccountId({
    accountIds,
    configuredDefaultAccountId: undefined,
  });
}

export function resolvePulseBoardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(
    opts.accountId ?? resolveDefaultPulseBoardAccountId(opts.cfg)
  );
  const pbCfg = (opts.cfg.channels as Record<string, unknown> | undefined)?.pulseboard;

  const privateKey = normalizeSecretInputString(pbCfg?.privateKey) ?? "";
  const configured = Boolean(privateKey);

  return {
    accountId,
    name: pbCfg?.name?.trim() || undefined,
    enabled: pbCfg?.enabled !== false,
    configured,
    privateKey,
    config: pbCfg,
  };
}
```

**Scoped (IRC pattern):**
```typescript
import { createAccountListHelpers } from "openclaw/plugin-sdk/account-helpers";
import { resolveMergedAccountConfig } from "openclaw/plugin-sdk/account-resolution";

const { listAccountIds: listPBAccountIds, resolveDefaultAccountId: resolveDefaultPBAccountId } =
  createAccountListHelpers("pulseboard", { normalizeAccountId });

function mergePBAccountConfig(cfg: CoreConfig, accountId: string): PulseBoardAccountConfig {
  return resolveMergedAccountConfig<PulseBoardAccountConfig>({
    channelConfig: cfg.channels?.pulseboard as PulseBoardAccountConfig | undefined,
    accounts: cfg.channels?.pulseboard?.accounts as Record<string, Partial<PulseBoardAccountConfig>> | undefined,
    accountId,
    normalizeAccountId,
    nestedObjectKeys: [], // if you have nested objects
  });
}

export function resolvePBAccount(params: {
  cfg: CoreConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(params.accountId ?? resolveDefaultPBAccountId(params.cfg));
  const merged = mergePBAccountConfig(params.cfg, accountId);

  return {
    accountId,
    enabled: merged.enabled !== false,
    configured: Boolean(merged.host && merged.nick),
    host: merged.host ?? "",
    port: merged.port ?? 6667,
    nick: merged.nick ?? "",
    config: merged,
  };
}
