### **11. Inbound Message Handling Pattern**

**Key functions (IRC example):**

```typescript
// src/inbound.ts
export async function handlePulseBoardInbound(params: {
  message: InboundMessage;
  account: ResolvedPulseBoardAccount;
  config: CoreConfig;
  runtime: RuntimeEnv;
  statusSink?: (patch: { lastInboundAt?: number }) => void;
}): Promise<void> {
  const { message, account, config, runtime, statusSink } = params;
  const core = getPulseBoardRuntime();

  // 1. Create pairing controller
  const pairing = createChannelPairingController({
    core,
    channel: "pulseboard",
    accountId: account.accountId,
  });

  // 2. Validate & parse message
  const rawBody = message.text?.trim() ?? "";
  if (!rawBody) return;

  // 3. Resolve sender access (DM policy)
  const resolvedAccess = await resolveDmPolicy({
    cfg: config,
    accountId: account.accountId,
    dmPolicy: account.config.dmPolicy ?? "pairing",
    allowFrom: account.config.allowFrom,
    senderId: message.senderId,
    rawBody,
    runtime,
  });

  if (resolvedAccess.access.decision !== "allow") {
    // log drop
    return;
  }

  // 4. Dispatch inbound to core
  await dispatchInboundDirectDmWithRuntime({
    cfg: config,
    runtime,
    channel: "pulseboard",
    channelLabel: "PulseBoard",
    accountId: account.accountId,
    peer: { kind: "direct", id: message.senderId },
    senderId: message.senderId,
    senderAddress: `pulseboard:${message.senderId}`,
    recipientAddress: `pulseboard:${account.publicKey}`,
    conversationLabel: message.senderId,
    rawBody: text,
    messageId: message.eventId,
    timestamp: message.createdAt,
    commandAuthorized: resolvedAccess.commandAuthorized,
    deliver: async (payload) => {
      // Handle reply from agent
      const outboundText = payload?.text ?? "";
      if (!outboundText.trim()) return;

      await sendPulseBoardMessage(message.senderId, outboundText, {
        accountId: account.accountId,
      });
    },
  });

  statusSink?.({ lastInboundAt: Date.now() });
}
```

