### 11. INBOUND MESSAGE HANDLING (`src/inbound.ts`)

Each plugin owns its inbound pipeline:

```typescript
export async function dispatchXxxInbound(params: {
  api: ChannelInboundApi;
  event: XxxEvent;
  runtime: PluginRuntime;
}): Promise<void> {
  const { api, event, runtime } = params;

  const account = resolveXxxAccount({
    cfg: runtime.config.loadConfig(),
    accountId: event.accountId,
  });

  // Validate sender
  const access = await resolveXxxDirectAccess({
    runtime,
    account,
    senderPubkey: event.from,
    rawBody: event.text,
  });

  if (access.kind !== "approved") {
    return; // DM security blocked it
  }

  // Convert platform message to OpenClaw inbound format
  await api.dispatchInbound({
    channel: "xxx",
    accountId: account.accountId,
    from: event.from,
    to: event.to,
    rawId: event.messageId,
    body: event.text,
    timestamp: event.timestamp,
    mediaUrls: event.attachments,
  });
}
```

**Key patterns:**
- Validate sender against DM security policy
- Parse raw message format to OpenClaw shape
- Include `rawId` for platform-specific message tracking
- Handle media URLs separately

