### 13. MESSAGE TARGET NORMALIZATION (`src/normalize.ts`)

Standardizes platform-specific message targets:

```typescript
export function normalizeXxxMessagingTarget(raw: string): string | null {
  const trimmed = raw.trim();
  if (!trimmed) return null;

  // Platform-specific normalization
  // e.g., "#" prefix for channels, "@" for users
  if (trimmed.startsWith("#")) {
    return trimmed.substring(1).toLowerCase();
  }

  return trimmed.toLowerCase();
}

export function looksLikeXxxTargetId(raw: string): boolean {
  return /^[a-z0-9_-]+$/.test(raw.toLowerCase());
}
```

Used by messaging adapter to validate targets before sending.

