### 15. SECURITY AND POLICIES (`src/policy.ts`)

DM access control and group message policies:

```typescript
export function resolveXxxDmPolicy(params: {
  account: ResolvedXxxAccount;
  senderKey: string;
}): DmSecurityResult {
  const { account } = params;

  const policy = account.config.dmPolicy ?? "pairing";
  const allowFrom = account.config.allowFrom ?? [];

  if (policy === "disabled") return { kind: "rejected" };
  if (policy === "open") return { kind: "approved" };

  if (policy === "allowlist") {
    const allowed = allowFrom.some((entry) =>
      normalizeXxxAllowEntry(entry) === params.senderKey
    );
    if (!allowed) return { kind: "requires_pairing" };
    return { kind: "approved" };
  }

  return { kind: "requires_pairing" };
}
```

