### 7. ACCOUNT RESOLUTION (`src/accounts.ts` and `src/types.ts`)

All plugins follow this pattern:

```typescript
import { createAccountListHelpers } from "openclaw/plugin-sdk/account-helpers";
import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";

export type ResolvedXxxAccount = {
  accountId: string;
  enabled: boolean;
  name?: string;
  configured: boolean;
  // Platform-specific fields
  token?: string;
  publicKey?: string;
  relays?: string[];
  // Original config object
  config: XxxAccountConfig;
};

const { 
  listAccountIds: listXxxAccountIds, 
  resolveDefaultAccountId: resolveDefaultXxxAccountId 
} = createAccountListHelpers("xxx", { normalizeAccountId });

export { listXxxAccountIds, resolveDefaultXxxAccountId };

export function resolveXxxAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedXxxAccount {
  const accountId = normalizeAccountId(
    opts.accountId ?? resolveDefaultXxxAccountId(opts.cfg)
  );

  const cfg = mergeXxxAccountConfig(opts.cfg, accountId);

  // Resolve secrets from env, files, or config
  const token = resolveToken(accountId, cfg);

  return {
    accountId,
    enabled: cfg.enabled ?? true,
    configured: !!token,
    token,
    config: cfg,
  };
}

function mergeXxxAccountConfig(cfg: OpenClawConfig, accountId: string): XxxAccountConfig {
  return resolveMergedAccountConfig<XxxAccountConfig>({
    channelConfig: cfg.channels?.xxx as XxxAccountConfig | undefined,
    accounts: cfg.channels?.xxx?.accounts as Record<string, Partial<XxxAccountConfig>> | undefined,
    accountId,
    omitKeys: ["defaultAccount"],
    normalizeAccountId,
  });
}
```

**Key patterns:**
- Use `resolveMergedAccountConfig()` to blend top-level and account-specific settings
- Support environment variables for secrets (e.g., `IRC_PASSWORD`, `TELEGRAM_TOKEN`)
- Support password/token files with `tryReadSecretFileSync()`
- Return both `enabled` (boolean) and `configured` (whether credentials exist)
- Always include original `config` object for downstream access

