### 14. STATUS MONITORING (`src/probe.ts` and `src/monitor.ts`)

Health checks and ongoing status updates:

```typescript
export async function probeXxx(params: {
  api: XxxApi;
  account: ResolvedXxxAccount;
}): Promise<BaseProbeResult> {
  try {
    const response = await params.api.get("/me");
    return {
      ok: true,
      issues: [],
    };
  } catch (err) {
    return {
      ok: false,
      issues: [
        {
          kind: "auth",
          message: "Token invalid or expired",
        },
      ],
    };
  }
}

export async function monitorXxx(params: {
  api: XxxApi;
  runtime: PluginRuntime;
}): Promise<void> {
  // Long-running connection monitor
  // For push-based protocols like Matrix, Telegram
  const bus = createXxxEventBus(params.api);

  bus.on("message", async (event) => {
    await dispatchXxxInbound({ api: params.api, event, runtime: params.runtime });
  });

  await bus.start();
}
```

