# PulseBoard Channel Plugin — Implementation Plan

## Context

Adding a fictional "PulseBoard" channel plugin to OpenClaw. PulseBoard is an imaginary
real-time bulletin board messaging platform supporting direct messages between users and
group posts to named "boards." The plugin must match the extension structure used by
existing bundled channel plugins (IRC, Nostr, Telegram) and follow all architecture
boundary rules.

Constraints:
- **Do NOT modify any existing files.** Only create new files under `extensions/pulseboard/`.
- `pulseboard` is not in core `src/channels/ids.ts` (`CHAT_CHANNEL_ORDER`), so the plugin
  meta must be supplied inline (no `getChatChannelMeta`), similar to how Nostr does it.
- There is no `openclaw/plugin-sdk/pulseboard` subpath. The extension's `runtime-api.ts`
  must import directly from existing public SDK subpaths (listed in
  `scripts/lib/plugin-sdk-entrypoints.json`).

---

## Design

### PulseBoard Concepts

| Concept         | Format                          | Notes                                         |
|-----------------|---------------------------------|-----------------------------------------------|
| Direct target   | `@username`                     | Lowercase alphanumeric + hyphens/underscores  |
| Board (group)   | `!board-name`                   | Lowercase alphanumeric + hyphens              |
| API auth        | Bearer `apiToken`               | Stored as secret input, env `PULSEBOARD_TOKEN`|
| API endpoint    | `https://api.pulseboard.example/` | Configurable per account                    |
| Chunk limit     | 4000 characters                 | Applied via `chunkTextForOutbound`            |

### Account Model

Scoped multi-account (IRC pattern): top-level `channels.pulseboard` provides defaults;
`channels.pulseboard.accounts.<id>` overrides per account. A single default account
is the common case.

### Supported Chat Types

`["direct", "group"]` — DMs and board messages.

---

## File Layout

All 25 files under `extensions/pulseboard/`:

```
extensions/pulseboard/
├── openclaw.plugin.json          # Plugin manifest
├── package.json                   # NPM metadata + openclaw channel config
├── index.ts                       # defineChannelPluginEntry
├── setup-entry.ts                 # defineSetupPluginEntry (lightweight)
├── api.ts                         # Public barrel (accounts + setup-surface)
├── runtime-api.ts                 # Private runtime barrel (SDK subpath imports)
├── channel-config-api.ts          # Re-exports PulseBoardChannelConfigSchema
└── src/
    ├── types.ts                   # CoreConfig, config types, inbound msg, probe type
    ├── accounts.ts                # createAccountListHelpers + resolveMergedAccountConfig
    ├── config-schema.ts           # Zod schema via buildChannelConfigSchema
    ├── config-ui-hints.ts         # ChannelConfigUiHints object
    ├── normalize.ts               # normalizeTarget, looksLikeId, normalizeAllowEntry
    ├── runtime.ts                 # createPluginRuntimeStore
    ├── policy.ts                  # Board policy helpers (requireMention, groupMatch)
    ├── send.ts                    # Outbound HTTP stub to fictional API
    ├── inbound.ts                 # handlePulseBoardInbound
    ├── monitor.ts                 # monitorPulseBoardProvider (connection loop)
    ├── probe.ts                   # probePulseBoard (GET /v1/me stub)
    ├── setup-core.ts              # ChannelSetupAdapter + config patch helpers
    ├── setup-surface.ts           # ChannelSetupWizard (token, username, endpoint)
    ├── channel.ts                 # createChatChannelPlugin export
    ├── channel.test.ts            # Plugin shape + chunker test
    ├── accounts.test.ts           # Account resolution tests
    ├── normalize.test.ts          # Target normalization tests
    └── config-schema.test.ts      # Zod schema validation tests
```

---

## Step-by-Step Implementation

### Step 1 — Manifest and Package Metadata

**`openclaw.plugin.json`**
```json
{
  "id": "pulseboard",
  "channels": ["pulseboard"],
  "configSchema": {
    "type": "object",
    "additionalProperties": false,
    "properties": {}
  }
}
```

**`package.json`** (key fields):
```json
{
  "name": "@openclaw/pulseboard",
  "version": "2026.4.1-beta.1",
  "type": "module",
  "openclaw": {
    "extensions": ["./index.ts"],
    "setupEntry": "./setup-entry.ts",
    "channel": {
      "id": "pulseboard",
      "label": "PulseBoard",
      "selectionLabel": "PulseBoard (API Token)",
      "detailLabel": "PulseBoard",
      "docsPath": "/channels/pulseboard",
      "docsLabel": "pulseboard",
      "blurb": "real-time bulletin board with direct messages and named board groups.",
      "aliases": ["pulse-board"],
      "systemImage": "rectangle.stack.badge.person.crop",
      "order": 110
    }
  }
}
```

---

### Step 2 — Type Definitions (`src/types.ts`)

Key types:

```typescript
// Per-board (group) configuration
type PulseBoardBoardConfig = {
  requireMention?: boolean;
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

// Per-account config (also used as top-level defaults)
type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  apiToken?: string;           // Secret; also read from PULSEBOARD_TOKEN env
  apiEndpoint?: string;        // Defaults to https://api.pulseboard.example/
  username?: string;           // Bot's @handle on PulseBoard
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  boards?: string[];           // !board-names to monitor
  groups?: Record<string, PulseBoardBoardConfig>;
  markdown?: MarkdownConfig;
};

// Top-level config with optional multi-account map
type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

// Resolved (secrets read, defaults applied)
type ResolvedPulseBoardAccount = {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;   // true when apiToken + username are present
  apiToken: string;
  apiEndpoint: string;
  username: string;
  config: PulseBoardAccountConfig;
};

// CoreConfig augments OpenClawConfig
type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

// Inbound message from platform
type PulseBoardInboundMessage = {
  messageId: string;
  senderUsername: string;    // @username of sender
  boardName?: string;        // !board-name if group message
  text: string;
  timestamp: number;
  isDirect: boolean;
};

// Probe result shape
type PulseBoardProbe = BaseProbeResult<string> & {
  apiEndpoint: string;
  username: string;
};
```

Import `DmPolicy`, `GroupPolicy`, `MarkdownConfig`, `OpenClawConfig`, `BaseProbeResult`
from `./runtime-api.js`.

---

### Step 3 — Runtime-API Barrel (`runtime-api.ts`)

Since no `openclaw/plugin-sdk/pulseboard` exists, import directly from available
public SDK subpaths:

```typescript
// Private runtime barrel for the bundled PulseBoard extension.
export { buildChannelConfigSchema } from "openclaw/plugin-sdk/channel-config-schema";
export type { ChannelPlugin } from "openclaw/plugin-sdk/channel-contract";
export type { BaseProbeResult } from "openclaw/plugin-sdk/channel-contract";
export {
  dispatchInboundDirectDmWithRuntime,
  resolveInboundDirectDmAccessWithRuntime,
  createPreCryptoDirectDmAuthorizer,
} from "openclaw/plugin-sdk/direct-dm";
export { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/account-id";
export {
  createDefaultChannelRuntimeState,
  collectStatusIssuesFromLastError,
} from "openclaw/plugin-sdk/status-helpers";
export { formatPairingApproveHint } from "openclaw/plugin-sdk/channel-pairing";
export { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
export {
  buildPassiveChannelStatusSummary,
  buildTrafficStatusSummary,
  resolveLoggerBackedRuntime,
  runStoppablePassiveMonitor,
} from "openclaw/plugin-sdk/extension-shared";
export { createChannelPairingController } from "openclaw/plugin-sdk/channel-pairing";
export { chunkTextForOutbound } from "openclaw/plugin-sdk/reply-chunking";
export type { OpenClawConfig } from "openclaw/plugin-sdk/config-runtime";
export type { PluginRuntime } from "openclaw/plugin-sdk/plugin-runtime";
export type { RuntimeEnv } from "openclaw/plugin-sdk/runtime-env";
export type {
  DmPolicy,
  GroupPolicy,
  MarkdownConfig,
} from "openclaw/plugin-sdk/config-runtime";
export {
  DmPolicySchema,
  GroupPolicySchema,
  MarkdownConfigSchema,
  requireOpenAllowFrom,
} from "openclaw/plugin-sdk/channel-config-schema";
```

> **Note:** Verify each subpath exists at implementation time by cross-referencing
> `scripts/lib/plugin-sdk-entrypoints.json` and looking at `src/plugin-sdk/irc.ts` and
> `src/plugin-sdk/nostr.ts` for the exact re-export source. Some types (e.g., `RuntimeEnv`,
> `PluginRuntime`) may need to come from `openclaw/plugin-sdk/irc` or
> `openclaw/plugin-sdk/nostr` until a generic subpath is confirmed. Adjust as needed.

---

### Step 4 — Account Resolution (`src/accounts.ts`)

Follow the IRC pattern using `createAccountListHelpers` + `resolveMergedAccountConfig`:

```typescript
import { createAccountListHelpers } from "openclaw/plugin-sdk/account-helpers";
import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import { resolveMergedAccountConfig } from "openclaw/plugin-sdk/account-resolution";
import { normalizeResolvedSecretInputString } from "openclaw/plugin-sdk/secret-input";

const { listAccountIds: listPulseBoardAccountIds,
        resolveDefaultAccountId: resolveDefaultPulseBoardAccountId } =
  createAccountListHelpers("pulseboard", { normalizeAccountId });

function mergePulseBoardAccountConfig(cfg: CoreConfig, accountId: string): PulseBoardAccountConfig {
  return resolveMergedAccountConfig<PulseBoardAccountConfig>({
    channelConfig: cfg.channels?.pulseboard as PulseBoardAccountConfig | undefined,
    accounts: cfg.channels?.pulseboard?.accounts as Record<string, Partial<PulseBoardAccountConfig>>,
    accountId,
    omitKeys: ["defaultAccount"],
    normalizeAccountId,
  });
}

export function resolvePulseBoardAccount(params: {
  cfg: CoreConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(
    params.accountId ?? resolveDefaultPulseBoardAccountId(params.cfg)
  );
  const merged = mergePulseBoardAccountConfig(params.cfg, accountId);

  // Token: config field, then env var for default account
  const envToken = accountId === DEFAULT_ACCOUNT_ID
    ? process.env.PULSEBOARD_TOKEN?.trim()
    : undefined;
  const configToken = normalizeResolvedSecretInputString({
    value: merged.apiToken,
    path: `channels.pulseboard.accounts.${accountId}.apiToken`,
  });
  const apiToken = configToken || envToken || "";

  // Username: config field, then env var for default account
  const username = (
    merged.username?.trim() ||
    (accountId === DEFAULT_ACCOUNT_ID ? process.env.PULSEBOARD_USERNAME?.trim() : "") ||
    ""
  ).trim();

  const apiEndpoint = (
    merged.apiEndpoint?.trim() || "https://api.pulseboard.example/"
  );

  return {
    accountId,
    name: merged.name?.trim() || undefined,
    enabled: merged.enabled !== false &&
             (cfg.channels?.pulseboard?.enabled !== false),
    configured: Boolean(apiToken && username),
    apiToken,
    apiEndpoint,
    username,
    config: merged,
  };
}

export { listPulseBoardAccountIds, resolveDefaultPulseBoardAccountId };

export function listEnabledPulseBoardAccounts(cfg: CoreConfig): ResolvedPulseBoardAccount[] {
  return listPulseBoardAccountIds(cfg)
    .map((accountId) => resolvePulseBoardAccount({ cfg, accountId }))
    .filter((a) => a.enabled);
}
```

