      config: {
        ...pulseBoardConfigAdapter,  // createScopedChannelConfigAdapter
        isConfigured: (account) => account.configured,
        describeAccount: (account) => describeAccountSnapshot({ account, configured: account.configured,
          extra: { apiEndpoint: account.apiEndpoint, username: account.username } }),
      },
      groups: {
        resolveRequireMention: ({ cfg, accountId, groupId }) => { /* use policy.ts */ },
        resolveToolPolicy: ({ cfg, accountId, groupId }) => { /* per-board tool policy */ },
      },
      messaging: {
        normalizeTarget: normalizePulseBoardMessagingTarget,
        targetResolver: {
          looksLikeId: looksLikePulseBoardTargetId,
          hint: "<@username|!board-name|pulseboard:@username>",
        },
      },
      resolver: {
        resolveTargets: async ({ inputs, kind }) => { /* map & validate */ },
      },
      directory: createChannelDirectoryAdapter({
        listPeers: async (params) => listPulseBoardDirectoryUsersFromConfig(params),
        listGroups: async (params) => listPulseBoardDirectoryBoardsFromConfig(params),
      }),
      status: createComputedAccountStatusAdapter<ResolvedPulseBoardAccount, PulseBoardProbe>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        buildChannelSummary: ({ account, snapshot }) => ({
          ...buildBaseChannelStatusSummary(snapshot),
          apiEndpoint: account.apiEndpoint,
          username: account.username,
          probe: snapshot.probe,
          lastProbeAt: snapshot.lastProbeAt ?? null,
        }),
        probeAccount: async ({ cfg, account, timeoutMs }) =>
          probePulseBoard(cfg as CoreConfig, { accountId: account.accountId, timeoutMs }),
        resolveAccountSnapshot: ({ account }) => ({
          accountId: account.accountId, name: account.name,
          enabled: account.enabled, configured: account.configured,
          extra: { apiEndpoint: account.apiEndpoint, username: account.username },
        }),
      }),
      gateway: {
        startAccount: async (ctx) => {
          const statusSink = createAccountStatusSink({ accountId: ctx.accountId, setStatus: ctx.setStatus });
          if (!ctx.account.configured) throw new Error("PulseBoard not configured.");
          ctx.log?.info(`[${ctx.accountId}] starting PulseBoard provider (@${ctx.account.username})`);
          await runStoppablePassiveMonitor({
            abortSignal: ctx.abortSignal,
            start: async () => monitorPulseBoardProvider({
              accountId: ctx.accountId,
              config: ctx.cfg as CoreConfig,
              runtime: ctx.runtime,
              abortSignal: ctx.abortSignal,
              statusSink,
            }),
