import { z } from "openclaw/plugin-sdk/zod";
import { pulseBoardChannelConfigUiHints } from "./config-ui-hints.js";

const PulseBoardBoardSchema = z.object({
  requireMention: z.boolean().optional(),
  enabled: z.boolean().optional(),
  allowFrom: z.array(z.union([z.string(), z.number()])).optional(),
  systemPrompt: z.string().optional(),
}).strict();

export const PulseBoardAccountSchemaBase = z.object({
  name: z.string().optional(),
  enabled: z.boolean().optional(),
  apiToken: z.string().optional(),
  apiEndpoint: z.string().url().optional(),
  username: z.string().optional(),
  dmPolicy: DmPolicySchema.optional().default("pairing"),
  allowFrom: z.array(z.union([z.string(), z.number()])).optional(),
  groupPolicy: GroupPolicySchema.optional().default("allowlist"),
  groupAllowFrom: z.array(z.union([z.string(), z.number()])).optional(),
  boards: z.array(z.string()).optional(),
  groups: z.record(z.string(), PulseBoardBoardSchema.optional()).optional(),
  markdown: MarkdownConfigSchema,
}).strict();

export const PulseBoardAccountSchema = PulseBoardAccountSchemaBase.superRefine((v, ctx) => {
  requireOpenAllowFrom({
    policy: v.dmPolicy,
    allowFrom: v.allowFrom,
    ctx,
    path: ["allowFrom"],
    message: 'channels.pulseboard.dmPolicy="open" requires channels.pulseboard.allowFrom to include "*"',
  });
});

export const PulseBoardConfigSchema = PulseBoardAccountSchemaBase.extend({
  accounts: z.record(z.string(), PulseBoardAccountSchema.optional()).optional(),
  defaultAccount: z.string().optional(),
}).superRefine((v, ctx) => {
  requireOpenAllowFrom({
    policy: v.dmPolicy,
    allowFrom: v.allowFrom,
    ctx,
    path: ["allowFrom"],
    message: 'channels.pulseboard.dmPolicy="open" requires channels.pulseboard.allowFrom to include "*"',
  });
});

export const PulseBoardChannelConfigSchema = buildChannelConfigSchema(
  PulseBoardConfigSchema,
  { uiHints: pulseBoardChannelConfigUiHints },
);
```

