### Step 6 — Normalize (`src/normalize.ts`)

```typescript
// Users:  @username  or  pulseboard:@username  → "@username"
// Boards: !board     or  pulseboard:!board     → "!board-name"

export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
  let trimmed = raw.trim();
  if (!trimmed) return undefined;
  const lower = trimmed.toLowerCase();
  if (lower.startsWith("pulseboard:")) {
    trimmed = trimmed.slice("pulseboard:".length).trim();
  }
  if (!trimmed) return undefined;
  if (!looksLikePulseBoardTargetId(trimmed)) return undefined;
  return trimmed.toLowerCase();
}

export function looksLikePulseBoardTargetId(raw: string): boolean {
  const t = raw.trim();
  if (!t) return false;
  return /^[@!][a-z0-9_-]+$/i.test(t);
}

export function isBoardTarget(target: string): boolean {
  return target.startsWith("!");
}

export function normalizePulseBoardAllowEntry(raw: string): string {
  let v = raw.trim().toLowerCase();
  if (v.startsWith("pulseboard:")) v = v.slice("pulseboard:".length);
  if (v.startsWith("@")) v = v.slice(1);
  return v.trim();
}
```

