### Step 2 — Type Definitions (`src/types.ts`)

Key types:

```typescript
// Per-board (group) configuration
type PulseBoardBoardConfig = {
  requireMention?: boolean;
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

// Per-account config (also used as top-level defaults)
type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  apiToken?: string;           // Secret; also read from PULSEBOARD_TOKEN env
  apiEndpoint?: string;        // Defaults to https://api.pulseboard.example/
  username?: string;           // Bot's @handle on PulseBoard
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  boards?: string[];           // !board-names to monitor
  groups?: Record<string, PulseBoardBoardConfig>;
  markdown?: MarkdownConfig;
};

// Top-level config with optional multi-account map
type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

// Resolved (secrets read, defaults applied)
type ResolvedPulseBoardAccount = {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;   // true when apiToken + username are present
  apiToken: string;
  apiEndpoint: string;
  username: string;
  config: PulseBoardAccountConfig;
};

// CoreConfig augments OpenClawConfig
type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

// Inbound message from platform
type PulseBoardInboundMessage = {
  messageId: string;
  senderUsername: string;    // @username of sender
  boardName?: string;        // !board-name if group message
  text: string;
  timestamp: number;
  isDirect: boolean;
};

// Probe result shape
type PulseBoardProbe = BaseProbeResult<string> & {
  apiEndpoint: string;
  username: string;
};
```

Import `DmPolicy`, `GroupPolicy`, `MarkdownConfig`, `OpenClawConfig`, `BaseProbeResult`
from `./runtime-api.js`.

