  createChatChannelPlugin({
    base: {
      id: "pulseboard",
      meta: {
        id: "pulseboard",
        label: "PulseBoard",
        selectionLabel: "PulseBoard (API Token)",
        docsPath: "/channels/pulseboard",
        docsLabel: "pulseboard",
        blurb: "real-time bulletin board with direct messages and named board groups.",
        order: 110,
      },
      capabilities: { chatTypes: ["direct", "group"], media: true, blockStreaming: true },
      reload: { configPrefixes: ["channels.pulseboard"] },
      configSchema: PulseBoardChannelConfigSchema,
      setup: pulseBoardSetupAdapter,
      setupWizard: pulseBoardSetupWizard,
      config: {
        ...pulseBoardConfigAdapter,  // createScopedChannelConfigAdapter
        isConfigured: (account) => account.configured,
        describeAccount: (account) => describeAccountSnapshot({ account, configured: account.configured,
          extra: { apiEndpoint: account.apiEndpoint, username: account.username } }),
      },
      groups: {
        resolveRequireMention: ({ cfg, accountId, groupId }) => { /* use policy.ts */ },
        resolveToolPolicy: ({ cfg, accountId, groupId }) => { /* per-board tool policy */ },
      },
      messaging: {
        normalizeTarget: normalizePulseBoardMessagingTarget,
        targetResolver: {
          looksLikeId: looksLikePulseBoardTargetId,
          hint: "<@username|!board-name|pulseboard:@username>",
        },
      },
      resolver: {
        resolveTargets: async ({ inputs, kind }) => { /* map & validate */ },
      },
      directory: createChannelDirectoryAdapter({
        listPeers: async (params) => listPulseBoardDirectoryUsersFromConfig(params),
        listGroups: async (params) => listPulseBoardDirectoryBoardsFromConfig(params),
      }),
      status: createComputedAccountStatusAdapter<ResolvedPulseBoardAccount, PulseBoardProbe>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        buildChannelSummary: ({ account, snapshot }) => ({
          ...buildBaseChannelStatusSummary(snapshot),
          apiEndpoint: account.apiEndpoint,
          username: account.username,
          probe: snapshot.probe,
          lastProbeAt: snapshot.lastProbeAt ?? null,
        }),
        probeAccount: async ({ cfg, account, timeoutMs }) =>
          probePulseBoard(cfg as CoreConfig, { accountId: account.accountId, timeoutMs }),
        resolveAccountSnapshot: ({ account }) => ({
          accountId: account.accountId, name: account.name,
          enabled: account.enabled, configured: account.configured,
          extra: { apiEndpoint: account.apiEndpoint, username: account.username },
        }),
      }),
      gateway: {
        startAccount: async (ctx) => {
          const statusSink = createAccountStatusSink({ accountId: ctx.accountId, setStatus: ctx.setStatus });
          if (!ctx.account.configured) throw new Error("PulseBoard not configured.");
          ctx.log?.info(`[${ctx.accountId}] starting PulseBoard provider (@${ctx.account.username})`);
          await runStoppablePassiveMonitor({
            abortSignal: ctx.abortSignal,
            start: async () => monitorPulseBoardProvider({
              accountId: ctx.accountId,
              config: ctx.cfg as CoreConfig,
              runtime: ctx.runtime,
              abortSignal: ctx.abortSignal,
              statusSink,
            }),
          });
        },
      },
    },
    pairing: {
      text: {
        idLabel: "pulseBoardUser",
        message: PAIRING_APPROVED_MESSAGE,
        normalizeAllowEntry: normalizePulseBoardAllowEntry,
        notify: async ({ id, message }) => {
          await sendMessagePulseBoard(`@${id}`, message);
        },
      },
    },
    security: {
      resolveDmPolicy: createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
        channelKey: "pulseboard",
        resolvePolicy: (account) => account.config.dmPolicy,
        resolveAllowFrom: (account) => account.config.allowFrom,
        policyPathSuffix: "dmPolicy",
        normalizeEntry: normalizePulseBoardAllowEntry,
      }),
      collectWarnings: composeAccountWarningCollectors<ResolvedPulseBoardAccount, any>(
        createAllowlistProviderOpenWarningCollector<ResolvedPulseBoardAccount>({
          providerConfigPresent: (cfg) => cfg.channels?.pulseboard !== undefined,
          resolveGroupPolicy: (account) => account.config.groupPolicy,
          buildOpenWarning: {
            surface: "PulseBoard boards",
            openBehavior: "allows all boards and senders (mention-gated)",
            remediation: 'Prefer channels.pulseboard.groupPolicy="allowlist" with channels.pulseboard.groups',
          },
        }),
      ),
    },
    outbound: {
      base: {
        deliveryMode: "direct",
        chunker: chunkTextForOutbound,
        chunkerMode: "markdown",
        textChunkLimit: 4000,
      },
      attachedResults: {
        channel: "pulseboard",
        sendText: async ({ cfg, to, text, accountId, replyToId }) =>
          sendMessagePulseBoard(to, text, {
            cfg: cfg as CoreConfig,
            accountId: accountId ?? undefined,
            replyTo: replyToId ?? undefined,
          }),
        sendMedia: async ({ cfg, to, text, mediaUrl, accountId, replyToId }) =>
          sendMessagePulseBoard(to, mediaUrl ? `${text}\n\nAttachment: ${mediaUrl}` : text, {
            cfg: cfg as CoreConfig, accountId: accountId ?? undefined,
          }),
      },
    },
  });
