  accountId: string;
  enabled: boolean;
  name?: string;
  configured: boolean;  // Has apiToken?
  apiToken: string;
  baseUrl: string;
  config: PulseBoardAccountConfig;
};

const { listAccountIds: listPulseBoardAccountIds, resolveDefaultAccountId: resolveDefaultPulseBoardAccountId } =
  createAccountListHelpers("pulseboard", { normalizeAccountId });

export { listPulseBoardAccountIds, resolveDefaultPulseBoardAccountId };

export function resolvePulseBoardAccount(opts: {
  cfg: CoreConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(opts.accountId ?? resolveDefaultPulseBoardAccountId(opts.cfg));
  const merged = mergePulseBoardAccountConfig(opts.cfg, accountId);
  const apiToken = resolveApiToken(accountId, merged);

  return {
    accountId,
    enabled: merged.enabled !== false,
    name: merged.name?.trim() || undefined,
    configured: Boolean(apiToken),
    apiToken,
    baseUrl: merged.baseUrl ?? "https://api.pulseboard.io",
    config: merged,
  };
}
