93	  });
94	}
95	
96	export const ircSetupAdapter: ChannelSetupAdapter = {
97	  resolveAccountId: ({ accountId }) => normalizeAccountId(accountId),
98	  applyAccountName: ({ cfg, accountId, name }) =>
99	    applyAccountNameToChannelSection({
100	      cfg,
101	      channelKey: channel,
