import type {
  BaseProbeResult,
  BlockStreamingCoalesceConfig,
  DmConfig,
  DmPolicy,
  GroupPolicy,
  GroupToolPolicyBySenderConfig,
  GroupToolPolicyConfig,
  MarkdownConfig,
  OpenClawConfig,
} from "./runtime-api.js";

// Per-board configuration (analogous to IrcChannelConfig).
export type PulseBoardBoardConfig = {
  requireMention?: boolean;
  tools?: GroupToolPolicyConfig;
  toolsBySender?: GroupToolPolicyBySenderConfig;
  skills?: string[];
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

// Per-account configuration fields shared with the top-level config.
export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  /** PulseBoard API token. Also reads PULSEBOARD_TOKEN env for the default account. */
  apiToken?: string;
  /** Base URL for the PulseBoard API (default: https://api.pulseboard.io). */
  baseUrl?: string;
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  defaultTo?: string;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  /** Per-board configuration keyed by board name (without ! prefix). */
  groups?: Record<string, PulseBoardBoardConfig>;
  /** Board names to subscribe to on connect (without ! prefix). */
  boards?: string[];
  markdown?: MarkdownConfig;
  historyLimit?: number;
  dmHistoryLimit?: number;
  dms?: Record<string, DmConfig>;
  textChunkLimit?: number;
  chunkMode?: "length" | "newline";
  blockStreaming?: boolean;
  blockStreamingCoalesce?: BlockStreamingCoalesceConfig;
  responsePrefix?: string;
  mediaMaxMb?: number;
};

// Top-level pulseboard config (base fields + optional accounts map).
export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

// Augmented core config type used throughout this extension.
export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

// Normalized inbound message from the PulseBoard polling API.
export type PulseBoardInboundMessage = {
  messageId: string;
  /**
   * Conversation target: board name (prefixed "!") for group messages,
   * sender username for DMs.
   */
  target: string;
  /** Raw API target field before normalization. */
  rawTarget?: string;
  senderUsername: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};

// Result of a connectivity probe against the PulseBoard API.
export type PulseBoardProbe = BaseProbeResult<string> & {
  baseUrl: string;
  username?: string;
  latencyMs?: number;
};

