// Target format conventions for PulseBoard:
//   Boards: !board-name  (analogous to IRC's #channel)
//   Users:  @username    (DM target; the @ is stripped in the canonical form)
//
// Canonical forms used internally:
//   Board: "!board-name" (always starts with !)
//   User:  "username"    (no prefix)

const PULSEBOARD_BOARD_PATTERN = /^![\w-]+$/u;
const PULSEBOARD_USER_PATTERN = /^[\w.-]+$/u;

/** Returns true when the raw string looks like a valid PulseBoard target id. */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  // Accept !board-name or @username or plain username
  if (trimmed.startsWith("!")) {
    return PULSEBOARD_BOARD_PATTERN.test(trimmed);
  }
  const stripped = trimmed.startsWith("@") ? trimmed.slice(1) : trimmed;
  return PULSEBOARD_USER_PATTERN.test(stripped);
}

/** Returns true when the canonical target is a board (starts with "!"). */
export function isPulseBoardBoardTarget(target: string): boolean {
  return target.startsWith("!");
}

/**
 * Normalizes a raw messaging target to its canonical form.
 *
 * Accepted prefixes: `pulseboard:`, `board:`, `user:`, `!`, `@`.
 * Returns undefined for empty or invalid inputs.
 */
export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
  let target = raw.trim();
  if (!target) {
    return undefined;
  }

  const lowered = target.toLowerCase();
  if (lowered.startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }

  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    // Ensure board prefix
    if (!target.startsWith("!")) {
      target = `!${target}`;
    }
  } else if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
    // Strip any leading @ that snuck in
    if (target.startsWith("@")) {
      target = target.slice(1).trim();
    }
  } else if (target.startsWith("@")) {
    // DM shorthand: @username → username
    target = target.slice(1).trim();
  }

  if (!target || !looksLikePulseBoardTargetId(target)) {
    return undefined;
  }

  return target;
}

/**
 * Normalizes an allowlist entry to a lowercase canonical form.
 * Strips `pulseboard:`, `user:`, and `@` prefixes.
 */
export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length);
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length);
  }
  if (value.startsWith("@")) {
    value = value.slice(1);
  }
  return value.trim();
}

export function normalizePulseBoardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? [])
    .map((entry) => normalizePulseBoardAllowEntry(String(entry)))
    .filter(Boolean);
}

export function resolvePulseBoardAllowlistMatch(params: {
  allowFrom: string[];
  senderUsername: string;
}): { allowed: boolean; source?: string } {
  const allowFrom = new Set(
    params.allowFrom.map((entry) => entry.trim().toLowerCase()).filter(Boolean),
  );
  if (allowFrom.has("*")) {
    return { allowed: true, source: "wildcard" };
  }
  const candidate = params.senderUsername.trim().toLowerCase();
  if (candidate && allowFrom.has(candidate)) {
    return { allowed: true, source: candidate };
  }
  return { allowed: false };
}

