import { resolvePulseBoardAccount } from "./accounts.js";
import {
  isPulseBoardBoardTarget,
  normalizePulseBoardMessagingTarget,
} from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseBoardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  replyTo?: string;
};

export type SendPulseBoardResult = {
  messageId: string;
  target: string;
};

function makePulseBoardMessageId(): string {
  return `pb-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
}

function recordPulseBoardOutboundActivity(accountId: string): void {
  try {
    getPulseBoardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (error) {
    if (!(error instanceof Error) || error.message !== "PulseBoard runtime not initialized") {
      throw error;
    }
  }
}

function resolveTarget(to: string): string {
  const normalized = normalizePulseBoardMessagingTarget(to);
  if (normalized) {
    return normalized;
  }
  throw new Error(`Invalid PulseBoard target: ${to}`);
}

/**
 * Sends a message to a PulseBoard board ("!board-name") or user ("username").
 *
 * Text is sent as-is; chunking is handled upstream by the outbound pipeline.
 * The function performs a single HTTP POST per call.
 */
export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({
    cfg,
    accountId: opts.accountId,
  });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiToken in channels.pulseboard).`,
    );
  }

  const target = resolveTarget(to);
  const payload = opts.replyTo ? `${text.trim()}\n\n[reply:${opts.replyTo}]` : text.trim();

  if (!payload) {
    throw new Error("Message must be non-empty for PulseBoard sends");
  }

  const isBoard = isPulseBoardBoardTarget(target);
  const boardName = isBoard ? target.slice(1) : undefined;
  const endpoint = isBoard
    ? `${account.baseUrl}/api/v1/boards/${encodeURIComponent(boardName!)}/messages`
    : `${account.baseUrl}/api/v1/dms/${encodeURIComponent(target)}`;

  const response = await fetch(endpoint, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${account.apiToken}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ text: payload }),
  });

  if (!response.ok) {
    throw new Error(
      `PulseBoard send failed: ${response.status} ${response.statusText} (target=${target})`,
    );
  }

  const json = (await response.json()) as { id?: string };
  const messageId = json.id ?? makePulseBoardMessageId();

  recordPulseBoardOutboundActivity(account.accountId);

  return { messageId, target };
}

