import { resolvePulseBoardAccount } from "./accounts.js";
import type { CoreConfig, PulseBoardProbe } from "./types.js";

function formatError(err: unknown): string {
  if (err instanceof Error) {
    return err.message;
  }
  return typeof err === "string" ? err : JSON.stringify(err);
}

/**
 * Probes the PulseBoard API by calling GET /api/v1/user/me and measuring
 * round-trip latency.
 */
export async function probePulseBoard(
  cfg: CoreConfig,
  opts?: { accountId?: string; timeoutMs?: number },
): Promise<PulseBoardProbe> {
  const account = resolvePulseBoardAccount({ cfg, accountId: opts?.accountId });
  const base: PulseBoardProbe = {
    ok: false,
    baseUrl: account.baseUrl,
  };

  if (!account.configured) {
    return {
      ...base,
      error: "missing apiToken",
    };
  }

  const endpoint = `${account.baseUrl}/api/v1/user/me`;
  const started = Date.now();

  try {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), opts?.timeoutMs ?? 8000);

    let response: Response;
    try {
      response = await fetch(endpoint, {
        headers: { Authorization: `Bearer ${account.apiToken}` },
        signal: controller.signal,
      });
    } finally {
      clearTimeout(timeoutId);
    }

    const latencyMs = Date.now() - started;

    if (!response.ok) {
      return {
        ...base,
        error: `HTTP ${response.status} ${response.statusText}`,
        latencyMs,
      };
    }

    const json = (await response.json()) as { username?: string };
    return {
      ...base,
      ok: true,
      username: json.username,
      latencyMs,
    };
  } catch (err) {
    return {
      ...base,
      error: formatError(err),
      latencyMs: Date.now() - started,
    };
  }
}

