import { resolveLoggerBackedRuntime } from "./runtime-api.js";
import { resolvePulseBoardAccount } from "./accounts.js";
import { handlePulseBoardInbound } from "./inbound.js";
import { isPulseBoardBoardTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";
import type { RuntimeEnv } from "./runtime-api.js";

/** Polling interval in milliseconds. */
const POLL_INTERVAL_MS = 3000;

export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  onMessage?: (message: PulseBoardInboundMessage) => void | Promise<void>;
};

/** Raw message shape returned by the PulseBoard poll endpoint. */
type PulseBoardApiMessage = {
  id: string;
  board?: string;
  sender: string;
  to?: string;
  text: string;
  timestamp: number;
  type: "board" | "dm";
};

/**
 * Constructs the canonical inbound target for a polled message.
 * Board messages use "!board-name"; DMs use the sender's username.
 */
export function resolvePulseBoardInboundTarget(msg: PulseBoardApiMessage): {
  isGroup: boolean;
  target: string;
  rawTarget: string;
} {
  if (msg.type === "board" && msg.board) {
    const target = msg.board.startsWith("!") ? msg.board : `!${msg.board}`;
    return { isGroup: true, target, rawTarget: msg.board };
  }
  return { isGroup: false, target: msg.sender, rawTarget: msg.to ?? msg.sender };
}

/**
 * Monitors PulseBoard for new messages by polling the REST API.
 *
 * Polls GET /api/v1/messages/poll?since={timestamp}&boards={b1,b2}
 * every POLL_INTERVAL_MS milliseconds until the abort signal fires.
 */
export async function monitorPulseBoardProvider(
  opts: PulseBoardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseBoardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
    opts.runtime,
    core.logging.getChildLogger(),
  );

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiToken in channels.pulseboard).`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  let stopped = false;
  let sinceTimestamp = Date.now();
  let pollTimer: ReturnType<typeof setTimeout> | null = null;

  const boards = (account.config.boards ?? []).join(",");
  const boardsQuery = boards ? `&boards=${encodeURIComponent(boards)}` : "";

  async function poll(): Promise<void> {
    if (stopped || opts.abortSignal?.aborted) {
      return;
    }

    const url = `${account.baseUrl}/api/v1/messages/poll?since=${sinceTimestamp}${boardsQuery}`;

    try {
      const response = await fetch(url, {
        headers: { Authorization: `Bearer ${account.apiToken}` },
        signal: opts.abortSignal,
      });

      if (!response.ok) {
        logger.warn?.(
          `[${account.accountId}] poll failed: ${response.status} ${response.statusText}`,
        );
      } else {
        const json = (await response.json()) as { messages?: PulseBoardApiMessage[] };
        const messages = json.messages ?? [];

        for (const raw of messages) {
          const inboundTarget = resolvePulseBoardInboundTarget(raw);
          const message: PulseBoardInboundMessage = {
            messageId: raw.id,
            target: inboundTarget.target,
            rawTarget: inboundTarget.rawTarget,
            senderUsername: raw.sender,
            text: raw.text,
            timestamp: raw.timestamp,
            isGroup: inboundTarget.isGroup,
          };

          // Advance the poll cursor past the newest message seen.
          if (raw.timestamp >= sinceTimestamp) {
            sinceTimestamp = raw.timestamp + 1;
          }

          core.channel.activity.record({
            channel: "pulseboard",
            accountId: account.accountId,
            direction: "inbound",
            at: message.timestamp,
          });

          if (opts.onMessage) {
            await opts.onMessage(message);
            continue;
          }

          await handlePulseBoardInbound({
            message,
            account,
            config: cfg,
            runtime,
            sendReply: async (target, text) => {
              const { sendMessagePulseBoard } = await import("./send.js");
              await sendMessagePulseBoard(target, text, {
                accountId: account.accountId,
              });
              opts.statusSink?.({ lastOutboundAt: Date.now() });
              core.channel.activity.record({
                channel: "pulseboard",
                accountId: account.accountId,
                direction: "outbound",
              });
            },
            statusSink: opts.statusSink,
          });
        }

        if (messages.length > 0) {
          logger.debug?.(
            `[${account.accountId}] processed ${messages.length} message(s)`,
          );
        }
      }
    } catch (err) {
      if ((err as Error)?.name === "AbortError") {
        return;
      }
      logger.error(`[${account.accountId}] poll error: ${String(err)}`);
    }

    if (!stopped && !opts.abortSignal?.aborted) {
      pollTimer = setTimeout(() => void poll(), POLL_INTERVAL_MS);
    }
  }

  // Validate board target format for configured boards.
  for (const board of account.config.boards ?? []) {
    const target = board.startsWith("!") ? board : `!${board}`;
    if (!isPulseBoardBoardTarget(target)) {
      logger.warn?.(
        `[${account.accountId}] skipping invalid board name: "${board}"`,
      );
    }
  }

  logger.info(
    `[${account.accountId}] starting PulseBoard monitor (${account.baseUrl}, polling every ${POLL_INTERVAL_MS}ms)`,
  );

  // Start the first poll immediately.
  void poll();

  opts.abortSignal?.addEventListener("abort", () => {
    stopped = true;
    if (pollTimer !== null) {
      clearTimeout(pollTimer);
      pollTimer = null;
    }
  });

  return {
    stop: () => {
      stopped = true;
      if (pollTimer !== null) {
        clearTimeout(pollTimer);
        pollTimer = null;
      }
    },
  };
}

