import { describe, expect, it } from "vitest";
import {
  listPulseBoardAccountIds,
  resolvePulseBoardAccount,
  resolveDefaultPulseBoardAccountId,
} from "./accounts.js";
import type { CoreConfig } from "./types.js";

function asConfig(value: unknown): CoreConfig {
  return value as CoreConfig;
}

describe("listPulseBoardAccountIds", () => {
  it("returns default when no accounts are configured", () => {
    expect(listPulseBoardAccountIds(asConfig({}))).toEqual(["default"]);
  });

  it("normalizes, deduplicates, and sorts configured account ids", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          accounts: {
            "Ops Team": {},
            "ops-team": {},
            Work: {},
          },
        },
      },
    });

    expect(listPulseBoardAccountIds(cfg)).toEqual(["ops-team", "work"]);
  });
});

describe("resolveDefaultPulseBoardAccountId", () => {
  it("prefers configured defaultAccount when it matches", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          defaultAccount: "Work",
          accounts: {
            default: {},
            work: {},
          },
        },
      },
    });

    expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("work");
  });

  it("falls back to default when configured defaultAccount is missing", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          defaultAccount: "missing",
          accounts: {
            default: {},
            work: {},
          },
        },
      },
    });

    expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("default");
  });

  it("falls back to first sorted account when default is absent", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          accounts: {
            zzz: {},
            aaa: {},
          },
        },
      },
    });

    expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("aaa");
  });
});

describe("resolvePulseBoardAccount", () => {
  it("resolves configured apiToken and reports configured=true", () => {
    const account = resolvePulseBoardAccount({
      cfg: asConfig({
        channels: {
          pulseboard: {
            apiToken: "tok-test-123",
          },
        },
      }),
    });

    expect(account.configured).toBe(true);
    expect(account.apiToken).toBe("tok-test-123");
  });

  it("reports configured=false when apiToken is absent", () => {
    const account = resolvePulseBoardAccount({
      cfg: asConfig({}),
    });

    expect(account.configured).toBe(false);
    expect(account.apiToken).toBe("");
  });

  it("uses the default base URL when none is configured", () => {
    const account = resolvePulseBoardAccount({
      cfg: asConfig({
        channels: { pulseboard: { apiToken: "tok" } },
      }),
    });

    expect(account.baseUrl).toBe("https://api.pulseboard.io");
  });

  it("strips trailing slashes from a custom base URL", () => {
    const account = resolvePulseBoardAccount({
      cfg: asConfig({
        channels: {
          pulseboard: {
            apiToken: "tok",
            baseUrl: "https://pb.internal.example.com/",
          },
        },
      }),
    });

    expect(account.baseUrl).toBe("https://pb.internal.example.com");
  });

  it("matches normalized configured account ids", () => {
    const account = resolvePulseBoardAccount({
      cfg: asConfig({
        channels: {
          pulseboard: {
            accounts: {
              "Ops Team": { apiToken: "tok-ops" },
            },
          },
        },
      }),
      accountId: "ops-team",
    });

    expect(account.accountId).toBe("ops-team");
    expect(account.configured).toBe(true);
    expect(account.apiToken).toBe("tok-ops");
  });

  it("reads PULSEBOARD_TOKEN env for the default account", () => {
    const prev = process.env.PULSEBOARD_TOKEN;
    process.env.PULSEBOARD_TOKEN = "env-tok-xyz";
    try {
      const account = resolvePulseBoardAccount({ cfg: asConfig({}) });
      expect(account.configured).toBe(true);
      expect(account.apiToken).toBe("env-tok-xyz");
    } finally {
      if (prev === undefined) {
        delete process.env.PULSEBOARD_TOKEN;
      } else {
        process.env.PULSEBOARD_TOKEN = prev;
      }
    }
  });
});

