import { describe, expect, it } from "vitest";
import {
  isPulseBoardBoardTarget,
  looksLikePulseBoardTargetId,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardAllowlist,
  normalizePulseBoardMessagingTarget,
  resolvePulseBoardAllowlistMatch,
} from "./normalize.js";

describe("looksLikePulseBoardTargetId", () => {
  it("accepts board targets", () => {
    expect(looksLikePulseBoardTargetId("!general")).toBe(true);
    expect(looksLikePulseBoardTargetId("!announcements")).toBe(true);
    expect(looksLikePulseBoardTargetId("!ops-team")).toBe(true);
  });

  it("accepts user targets", () => {
    expect(looksLikePulseBoardTargetId("alice")).toBe(true);
    expect(looksLikePulseBoardTargetId("@bob")).toBe(true);
    expect(looksLikePulseBoardTargetId("user.name")).toBe(true);
  });

  it("rejects empty and whitespace strings", () => {
    expect(looksLikePulseBoardTargetId("")).toBe(false);
    expect(looksLikePulseBoardTargetId("   ")).toBe(false);
  });

  it("rejects strings with spaces", () => {
    expect(looksLikePulseBoardTargetId("hello world")).toBe(false);
  });
});

describe("isPulseBoardBoardTarget", () => {
  it("returns true for !-prefixed targets", () => {
    expect(isPulseBoardBoardTarget("!general")).toBe(true);
  });

  it("returns false for user targets", () => {
    expect(isPulseBoardBoardTarget("alice")).toBe(false);
    expect(isPulseBoardBoardTarget("@alice")).toBe(false);
  });
});

describe("normalizePulseBoardMessagingTarget", () => {
  it("returns board target with ! prefix", () => {
    expect(normalizePulseBoardMessagingTarget("!general")).toBe("!general");
    expect(normalizePulseBoardMessagingTarget("board:general")).toBe("!general");
    expect(normalizePulseBoardMessagingTarget("pulseboard:board:ops")).toBe("!ops");
  });

  it("returns user target without @ prefix", () => {
    expect(normalizePulseBoardMessagingTarget("@alice")).toBe("alice");
    expect(normalizePulseBoardMessagingTarget("alice")).toBe("alice");
    expect(normalizePulseBoardMessagingTarget("user:bob")).toBe("bob");
    expect(normalizePulseBoardMessagingTarget("pulseboard:user:carol")).toBe("carol");
  });

  it("strips the pulseboard: prefix before routing", () => {
    expect(normalizePulseBoardMessagingTarget("pulseboard:alice")).toBe("alice");
  });

  it("returns undefined for empty or whitespace input", () => {
    expect(normalizePulseBoardMessagingTarget("")).toBeUndefined();
    expect(normalizePulseBoardMessagingTarget("   ")).toBeUndefined();
    expect(normalizePulseBoardMessagingTarget("\n")).toBeUndefined();
  });

  it("returns undefined for targets with spaces", () => {
    expect(normalizePulseBoardMessagingTarget("hello world")).toBeUndefined();
  });
});

describe("normalizePulseBoardAllowEntry", () => {
  it("lowercases and strips prefixes", () => {
    expect(normalizePulseBoardAllowEntry("Alice")).toBe("alice");
    expect(normalizePulseBoardAllowEntry("@Bob")).toBe("bob");
    expect(normalizePulseBoardAllowEntry("user:Carol")).toBe("carol");
    expect(normalizePulseBoardAllowEntry("pulseboard:Dave")).toBe("dave");
    expect(normalizePulseBoardAllowEntry("pulseboard:user:Eve")).toBe("eve");
  });

  it("preserves wildcard", () => {
    expect(normalizePulseBoardAllowEntry("*")).toBe("*");
  });

  it("returns empty string for blank input", () => {
    expect(normalizePulseBoardAllowEntry("")).toBe("");
    expect(normalizePulseBoardAllowEntry("   ")).toBe("");
  });
});

describe("normalizePulseBoardAllowlist", () => {
  it("normalizes and filters blank entries", () => {
    expect(normalizePulseBoardAllowlist(["Alice", "@Bob", ""])).toEqual(["alice", "bob"]);
  });

  it("handles numeric entries by stringifying", () => {
    expect(normalizePulseBoardAllowlist([42 as unknown as string])).toEqual(["42"]);
  });
});

describe("resolvePulseBoardAllowlistMatch", () => {
  it("allows when sender is in the allowlist", () => {
    expect(
      resolvePulseBoardAllowlistMatch({ allowFrom: ["alice", "bob"], senderUsername: "Alice" })
        .allowed,
    ).toBe(true);
  });

  it("allows when allowlist contains wildcard", () => {
    expect(
      resolvePulseBoardAllowlistMatch({ allowFrom: ["*"], senderUsername: "unknown" }).allowed,
    ).toBe(true);
  });

  it("denies when sender is not in the allowlist", () => {
    expect(
      resolvePulseBoardAllowlistMatch({ allowFrom: ["alice"], senderUsername: "eve" }).allowed,
    ).toBe(false);
  });

  it("denies when allowlist is empty", () => {
    expect(
      resolvePulseBoardAllowlistMatch({ allowFrom: [], senderUsername: "alice" }).allowed,
    ).toBe(false);
  });
});

