import { describe, expect, it } from "vitest";
import { PulseBoardConfigSchema } from "./config-schema.js";

describe("PulseBoardConfigSchema", () => {
  it("accepts a minimal config with just apiToken", () => {
    const parsed = PulseBoardConfigSchema.parse({ apiToken: "tok-abc" });
    expect(parsed.apiToken).toBe("tok-abc");
    expect(parsed.dmPolicy).toBe("pairing");
    expect(parsed.groupPolicy).toBe("allowlist");
  });

  it("accepts numeric allowFrom and groupAllowFrom entries", () => {
    const parsed = PulseBoardConfigSchema.parse({
      dmPolicy: "allowlist",
      allowFrom: [12345, "alice"],
      groupAllowFrom: [67890, "bob"],
    });

    expect(parsed.allowFrom).toEqual([12345, "alice"]);
    expect(parsed.groupAllowFrom).toEqual([67890, "bob"]);
  });

  it("accepts per-board allowFrom with numeric entries", () => {
    const parsed = PulseBoardConfigSchema.parse({
      groups: {
        general: { allowFrom: [42, "alice"] },
      },
    });

    expect(parsed.groups?.general?.allowFrom).toEqual([42, "alice"]);
  });

  it("accepts an accounts map", () => {
    const parsed = PulseBoardConfigSchema.parse({
      accounts: {
        work: { apiToken: "tok-work" },
        personal: { apiToken: "tok-personal", baseUrl: "https://pb.personal.example.com" },
      },
      defaultAccount: "work",
    });

    expect(parsed.accounts?.work?.apiToken).toBe("tok-work");
    expect(parsed.accounts?.personal?.baseUrl).toBe("https://pb.personal.example.com");
    expect(parsed.defaultAccount).toBe("work");
  });

  it("rejects dmPolicy=open without wildcard allowFrom", () => {
    const result = PulseBoardConfigSchema.safeParse({
      dmPolicy: "open",
      allowFrom: ["alice"],
    });

    expect(result.success).toBe(false);
    if (!result.success) {
      const paths = result.error.issues.map((i) => i.path.join("."));
      expect(paths).toContain("allowFrom");
    }
  });

  it("accepts dmPolicy=open with wildcard allowFrom", () => {
    const parsed = PulseBoardConfigSchema.parse({
      dmPolicy: "open",
      allowFrom: ["*"],
    });

    expect(parsed.dmPolicy).toBe("open");
  });

  it("accepts board config with requireMention override", () => {
    const parsed = PulseBoardConfigSchema.parse({
      groups: {
        general: { requireMention: false },
        ops: { requireMention: true, systemPrompt: "Focus on ops." },
      },
    });

    expect(parsed.groups?.general?.requireMention).toBe(false);
    expect(parsed.groups?.ops?.requireMention).toBe(true);
    expect(parsed.groups?.ops?.systemPrompt).toBe("Focus on ops.");
  });
});

